import React, { useState, useEffect } from 'react';
import { HierarchyService, UserService, NotificationService, ReferentService } from '../services/firebaseBackend';
import { User, FullHierarchy, ProcessNode, DocType, UserRole, Referent } from '../types';
import { 
  FolderTree, Search, ChevronRight, ChevronDown, Plus, X, Edit, Users, CheckSquare, Square, Filter, RefreshCw, AlertCircle, Link, Layers, Trash2, Loader2, UserCheck, Briefcase
} from 'lucide-react';

interface Props {
  user: User;
}

const AdminAssignments: React.FC<Props> = ({ user }) => {
  const [hierarchy, setHierarchy] = useState<FullHierarchy>({});
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [allReferents, setAllReferents] = useState<Referent[]>([]);
  const [loading, setLoading] = useState(true);
  const [seeding, setSeeding] = useState(false);

  const [filterProject, setFilterProject] = useState('');
  const [filterMacro, setFilterMacro] = useState('');
  const [filterProcess, setFilterProcess] = useState('');
  const [filterMicro, setFilterMicro] = useState(''); 
  const [filterAnalyst, setFilterAnalyst] = useState('');

  const [expandedProjects, setExpandedProjects] = useState<Record<string, boolean>>({ 'HPC': true, 'HSR': true });

  // Edit Assignment Modal State
  const [showEditModal, setShowEditModal] = useState(false);
  const [modalProject, setModalProject] = useState('');
  const [modalMicro, setModalMicro] = useState('');
  const [modalProcess, setModalProcess] = useState('');
  const [currentAssignees, setCurrentAssignees] = useState<string[]>([]);
  const [currentReferents, setCurrentReferents] = useState<string[]>([]);
  const [matrixKeyToUpdate, setMatrixKeyToUpdate] = useState<string | null>(null);

  useEffect(() => { loadData(); }, []);

  const loadData = async (showLoader = true) => {
    if (showLoader) setLoading(true);
    try {
        const [h, u, r] = await Promise.all([
          HierarchyService.getFullHierarchy(),
          UserService.getAll(),
          ReferentService.getAll()
        ]);
        setHierarchy(h);
        setAllUsers(u);
        setAllReferents(r);
    } catch (e) { console.error(e); } finally { if (showLoader) setLoading(false); }
  };

  const handleEditAssignment = (proj: string, macro: string, proc: string, microObj: ProcessNode) => {
      setModalProject(proj);
      setModalProcess(proc);
      setModalMicro(microObj.name);
      setMatrixKeyToUpdate(microObj.docId);
      setCurrentAssignees([...(microObj.assignees || [])]);
      setCurrentReferents([...(microObj.referentIds || [])]);
      setShowEditModal(true);
  };

  const handleSubmitAssignment = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!matrixKeyToUpdate) return;
      try {
          await HierarchyService.updateMatrixAssignment(matrixKeyToUpdate, currentAssignees, currentReferents);
          setShowEditModal(false);
          await loadData(false); 
      } catch (err: any) { alert(err.message); }
  };

  const getFlattenedRows = (project: string) => {
      const rows: any[] = [];
      const macros = hierarchy[project] || {};
      Object.keys(macros).forEach(macro => {
          if (filterMacro && macro !== filterMacro) return;
          Object.keys(macros[macro]).forEach(proc => {
              if (filterProcess && proc !== filterProcess) return;
              macros[macro][proc].forEach(node => {
                  if (node.active === false) return; 
                  if (filterMicro && !node.name.toLowerCase().includes(filterMicro.toLowerCase())) return;
                  if (filterAnalyst && (!node.assignees || !node.assignees.includes(filterAnalyst))) return;
                  rows.push({ macro, proc, node });
              });
          });
      });
      return rows;
  };

  if (loading) return <div className="p-8 text-center text-slate-500">Cargando matriz...</div>;

  return (
    <div className="space-y-6 pb-12">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">Gestor de Asignaciones</h1>
          <p className="text-slate-500">Asigne analistas responsables y referentes técnicos.</p>
        </div>
      </div>

      <div className="space-y-4">
        {Object.keys(hierarchy).map(projectKey => {
            if (filterProject && projectKey !== filterProject) return null;
            const rows = getFlattenedRows(projectKey);
            if (rows.length === 0) return null;
            return (
                <div key={projectKey} className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                    <div onClick={() => setExpandedProjects(prev => ({...prev, [projectKey]: !prev[projectKey]}))} className="flex items-center justify-between p-4 bg-slate-50 hover:bg-slate-100 cursor-pointer border-b border-slate-200">
                        <div className="flex items-center gap-2 font-bold text-slate-800 text-lg">
                            {expandedProjects[projectKey] ? <ChevronDown size={20} /> : <ChevronRight size={20} />}
                            <FolderTree size={20} className="text-indigo-600" /> Proyecto {projectKey}
                        </div>
                    </div>
                    {expandedProjects[projectKey] && (
                        <div className="overflow-x-auto">
                            <table className="w-full text-sm text-left">
                                <thead className="text-xs text-slate-500 uppercase bg-slate-50/50">
                                    <tr>
                                        <th className="px-4 py-3">Microproceso</th>
                                        <th className="px-4 py-3">Analistas (Elaboración)</th>
                                        <th className="px-4 py-3">Referentes (Validación)</th>
                                        <th className="px-4 py-3 text-right">Acciones</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-100">
                                    {rows.map((row, idx) => (
                                        <tr key={`${row.node.docId}-${idx}`} className="hover:bg-slate-50">
                                            <td className="px-4 py-3 align-top">
                                                <div className="font-bold text-slate-900">{row.node.name}</div>
                                                <div className="text-[10px] text-slate-500">{row.proc}</div>
                                            </td>
                                            <td className="px-4 py-3 align-top">
                                                <div className="text-xs text-slate-600">
                                                    {row.node.assignees?.length > 0 ? row.node.assignees.map((aid:string) => allUsers.find(u => u.id === aid)?.name).join(', ') : <span className="text-red-400 italic">Sin asignar</span>}
                                                </div>
                                            </td>
                                            <td className="px-4 py-3 align-top">
                                                <div className="text-xs text-indigo-600">
                                                    {row.node.referentIds?.length > 0 ? row.node.referentIds.map((rid:string) => allReferents.find(r => r.id === rid)?.name).join(', ') : <span className="text-slate-400 italic">Sin referentes</span>}
                                                </div>
                                            </td>
                                            <td className="px-4 py-3 align-top text-right">
                                                <button onClick={() => handleEditAssignment(projectKey, row.macro, row.proc, row.node)} className="text-slate-400 hover:text-indigo-600 p-1.5 hover:bg-indigo-50 rounded transition-colors"><Edit size={16} /></button>
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    )}
                </div>
            );
        })}
      </div>

      {showEditModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fadeIn">
            <div className="bg-white rounded-xl shadow-xl w-full max-w-2xl overflow-hidden">
                <div className="p-5 border-b border-slate-100 bg-slate-50/50 flex justify-between items-center">
                    <h3 className="text-lg font-bold text-slate-800">Gestionar Responsables: {modalMicro}</h3>
                    <button onClick={() => setShowEditModal(false)} className="text-slate-400 hover:text-slate-600"><X size={20} /></button>
                </div>
                <form onSubmit={handleSubmitAssignment} className="p-6 space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                        {/* ANALISTAS */}
                        <div className="space-y-3">
                            <h4 className="font-bold text-sm text-slate-700 flex items-center gap-2 border-b border-slate-100 pb-2"><Users size={16} className="text-blue-500" /> Analistas Responsables</h4>
                            <div className="space-y-1 max-h-48 overflow-y-auto border border-slate-200 rounded-lg p-2">
                                {allUsers.filter(u => u.role === UserRole.ANALYST).map(u => (
                                    <label key={u.id} className="flex items-center gap-2 p-1.5 hover:bg-slate-50 rounded cursor-pointer">
                                        <input 
                                            type="checkbox" 
                                            checked={currentAssignees.includes(u.id)}
                                            onChange={(e) => {
                                                if (e.target.checked) setCurrentAssignees([...currentAssignees, u.id]);
                                                else setCurrentAssignees(currentAssignees.filter(id => id !== u.id));
                                            }}
                                            className="w-4 h-4 text-indigo-600 border-slate-300 rounded focus:ring-indigo-500"
                                        />
                                        <span className="text-xs text-slate-700">{u.name}</span>
                                    </label>
                                ))}
                            </div>
                        </div>

                        {/* REFERENTES */}
                        <div className="space-y-3">
                            <h4 className="font-bold text-sm text-indigo-700 flex items-center gap-2 border-b border-slate-100 pb-2"><UserCheck size={16} className="text-indigo-500" /> Referentes Técnicos</h4>
                            <div className="space-y-1 max-h-48 overflow-y-auto border border-slate-200 rounded-lg p-2">
                                {allReferents.map(r => (
                                    <label key={r.id} className="flex items-center gap-2 p-1.5 hover:bg-indigo-50/50 rounded cursor-pointer">
                                        <input 
                                            type="checkbox" 
                                            checked={currentReferents.includes(r.id)}
                                            onChange={(e) => {
                                                if (e.target.checked) setCurrentReferents([...currentReferents, r.id]);
                                                else setCurrentReferents(currentReferents.filter(id => id !== r.id));
                                            }}
                                            className="w-4 h-4 text-indigo-600 border-slate-300 rounded focus:ring-indigo-500"
                                        />
                                        <div>
                                            <p className="text-xs text-slate-800 font-medium">{r.name}</p>
                                            <p className="text-[10px] text-slate-500">{r.specialty}</p>
                                        </div>
                                    </label>
                                ))}
                            </div>
                        </div>
                    </div>

                    <div className="flex justify-end pt-6 gap-3 border-t border-slate-100">
                        <button type="button" onClick={() => setShowEditModal(false)} className="px-4 py-2 text-slate-600 font-medium">Cancelar</button>
                        <button type="submit" className="px-6 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 font-bold shadow-md">Guardar Cambios</button>
                    </div>
                </form>
            </div>
          </div>
      )}
    </div>
  );
};

export default AdminAssignments;

import React, { useEffect, useState, useRef } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import { DocumentService, HistoryService, UserService, HierarchyService, ReferentService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, DocHistory, UserRole, DocState, FullHierarchy, Referent } from '../types';
import { STATE_CONFIG } from '../constants';
import { parseDocumentFilename, validateCoordinatorRules, getCoordinatorRuleHint } from '../utils/filenameParser';
import { ArrowLeft, FileText, CheckCircle, XCircle, Activity, Mail, MessageSquare, ExternalLink, Trash2, Lock, Save, PlusCircle, Upload, Loader2, UserCheck } from 'lucide-react';

interface Props {
  user: User;
}

const DocumentDetail: React.FC<Props> = ({ user }) => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const location = useLocation(); 

  const [doc, setDoc] = useState<Document | null>(null);
  const [history, setHistory] = useState<DocHistory[]>([]);
  const [assigneeEmails, setAssigneeEmails] = useState<string[]>([]);
  const [referentEmails, setReferentEmails] = useState<string[]>([]);
  const [coordinatorEmail, setCoordinatorEmail] = useState<string>('');
  const [loading, setLoading] = useState(true);
  const [comment, setComment] = useState('');
  const [actionLoading, setActionLoading] = useState(false);
  const [showResponseModal, setShowResponseModal] = useState(false);
  const [pendingAction, setPendingAction] = useState<'APPROVE' | 'REJECT' | null>(null);
  const [responseFile, setResponseFile] = useState<File | null>(null);
  const [isFileValid, setIsFileValid] = useState(false);
  const [detectedVersion, setDetectedVersion] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (id) loadData(id);
  }, [id]);

  const loadData = async (docId: string) => {
    setLoading(true);
    try {
        const [d, h, allUsers, hierarchy, allReferents] = await Promise.all([
          DocumentService.getById(docId),
          HistoryService.getHistory(docId),
          UserService.getAll(),
          HierarchyService.getFullHierarchy(),
          ReferentService.getAll()
        ]);
        if (d) {
            setDoc(d);
            setHistory(h);
            const coord = allUsers.find(u => u.role === UserRole.COORDINATOR || u.role === UserRole.ADMIN);
            if (coord) setCoordinatorEmail(coord.email);

            // Resolve emails from Hierarchy Matrix
            const targetMicro = normalizeHeader(d.microprocess || '');
            const targetProject = normalizeHeader(d.project || '');
            let node = null;
            for (const p of Object.keys(hierarchy)) {
                if (normalizeHeader(p) === targetProject) {
                    for (const m of Object.keys(hierarchy[p])) {
                        for (const proc of Object.keys(hierarchy[p][m])) {
                            const found = hierarchy[p][m][proc].find(n => normalizeHeader(n.name) === targetMicro);
                            if (found) { node = found; break; }
                        }
                        if (node) break;
                    }
                }
                if (node) break;
            }

            if (node) {
                const aEmails = (node.assignees || []).map(aid => allUsers.find(u => u.id === aid)?.email).filter(e => e) as string[];
                setAssigneeEmails(aEmails);
                const rEmails = (node.referentIds || []).map(rid => allReferents.find(ref => ref.id === rid)?.email).filter(e => e) as string[];
                setReferentEmails(rEmails);
            }
        }
    } catch (e) { console.error(e); } finally { setLoading(false); }
  };

  const handleNotifyReferent = () => {
      if (!doc) return;
      const subject = encodeURIComponent(`Solicitud de Aprobación Técnica: ${doc.microprocess || ''}`);
      const to = encodeURIComponent(referentEmails.join(','));
      const cc = encodeURIComponent(assigneeEmails.join(','));
      const body = encodeURIComponent(`Estimados,\nPara vuestra validación técnica, adjunto el Informe:\n- ${doc.microprocess} - ${doc.docType || ''} - ${doc.version}\n\nAtento a comentarios.\nSaludos,\n${user.name}`);
      window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${to}&cc=${cc}&su=${subject}&body=${body}`, '_blank');
  };

  const handleActionClick = async (action: any) => {
      if (action === 'APPROVE' || action === 'REJECT') {
          setPendingAction(action); setShowResponseModal(true);
      } else {
          setActionLoading(true);
          await DocumentService.transitionState(doc!.id, user, action, comment);
          setComment(''); await loadData(doc!.id);
          setActionLoading(false);
      }
  };

  if (loading) return <div className="p-8 text-center text-slate-500">Cargando...</div>;
  if (!doc) return <div>No encontrado</div>;

  const config = STATE_CONFIG[doc.state];
  const isCoordinator = user.role === UserRole.COORDINATOR || user.role === UserRole.ADMIN;
  const showNotifyReferent = isCoordinator && (doc.state === DocState.SENT_TO_REFERENT || doc.state === DocState.REFERENT_REVIEW);

  return (
    <div className="max-w-4xl mx-auto space-y-6 pb-12">
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
        <div className="flex justify-between gap-4 mb-6">
            <div>
                <div className="flex items-center gap-2 mb-1">
                    <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-slate-800 text-white">{doc.project}</span>
                    <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-indigo-100 text-indigo-700">{doc.docType}</span>
                </div>
                <h1 className="text-2xl font-bold text-slate-900">{doc.title}</h1>
            </div>
            <div className={`px-3 py-1.5 rounded-lg text-sm font-semibold h-fit ${config.color}`}>{config.label}</div>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-sm border-t border-slate-100 pt-4">
