import { 
  FolderTree, ChevronRight, ChevronDown, X, Edit, Users, Loader2
} from 'lucide-react';

interface Props {
  user: User;
}

const AdminAssignments: React.FC<Props> = ({ user }) => {
  const [hierarchy, setHierarchy] = useState<FullHierarchy>({});
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);

  const [filterProject, setFilterProject] = useState('');
  const [filterMacro, setFilterMacro] = useState('');
  const [filterProcess, setFilterProcess] = useState('');
  const [filterMicro, setFilterMicro] = useState(''); 
  const [filterAnalyst, setFilterAnalyst] = useState('');

  const [expandedProjects, setExpandedProjects] = useState<Record<string, boolean>>({ 'HPC': true, 'HSR': true });

  // Edit Assignment Modal State
  const [showEditModal, setShowEditModal] = useState(false);
  const [modalMicro, setModalMicro] = useState('');
  const [currentAssignees, setCurrentAssignees] = useState<string[]>([]);
  const [matrixKeyToUpdate, setMatrixKeyToUpdate] = useState<string | null>(null);

  useEffect(() => { loadData(); }, []);

  const loadData = async (showLoader = true) => {
    if (showLoader) setLoading(true);
    try {
        const [h, u] = await Promise.all([
          HierarchyService.getFullHierarchy(),
          UserService.getAll()
        ]);
        setHierarchy(h);
        setAllUsers(u);
    } catch (e) { console.error(e); } finally { if (showLoader) setLoading(false); }
  };

  const handleEditAssignment = (proj: string, macro: string, proc: string, microObj: ProcessNode) => {
      setModalMicro(microObj.name);
      setMatrixKeyToUpdate(microObj.docId);
      setCurrentAssignees([...(microObj.assignees || [])]);
      setShowEditModal(true);
  };

  const handleSubmitAssignment = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!matrixKeyToUpdate) return;
      try {
          await HierarchyService.updateMatrixAssignment(matrixKeyToUpdate, currentAssignees);
          setShowEditModal(false);
          await loadData(false); 
      } catch (err: any) { alert(err.message); }
  };

  const getFlattenedRows = (project: string) => {
      const rows: any[] = [];
      const macros = hierarchy[project] || {};
      Object.keys(macros).forEach(macro => {
          if (filterMacro && macro !== filterMacro) return;
          Object.keys(macros[macro]).forEach(proc => {
              if (filterProcess && proc !== filterProcess) return;
              macros[macro][proc].forEach(node => {
                  if (node.active === false) return; 
                  if (filterMicro && !node.name.toLowerCase().includes(filterMicro.toLowerCase())) return;
                  if (filterAnalyst && (!node.assignees || !node.assignees.includes(filterAnalyst))) return;
                  rows.push({ macro, proc, node });
              });
          });
      });
      return rows;
  };

  if (loading) return <div className="p-8 text-center text-slate-500">Cargando matriz...</div>;

  return (
    <div className="space-y-6 pb-12">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">Gestor de Asignaciones</h1>
          <p className="text-slate-500">Asigne analistas responsables para la elaboración de documentos.</p>
        </div>
      </div>

      <div className="space-y-4">
        {Object.keys(hierarchy).map(projectKey => {
            if (filterProject && projectKey !== filterProject) return null;
            const rows = getFlattenedRows(projectKey);
            if (rows.length === 0) return null;
            return (
                <div key={projectKey} className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                    <div onClick={() => setExpandedProjects(prev => ({...prev, [projectKey]: !prev[projectKey]}))} className="flex items-center justify-between p-4 bg-slate-50 hover:bg-slate-100 cursor-pointer border-b border-slate-200">
                        <div className="flex items-center gap-2 font-bold text-slate-800 text-lg">
                            {expandedProjects[projectKey] ? <ChevronDown size={20} /> : <ChevronRight size={20} />}
                            <FolderTree size={20} className="text-indigo-600" /> Proyecto {projectKey}
                        </div>
                    </div>
                    {expandedProjects[projectKey] && (
                        <div className="overflow-x-auto">
                            <table className="w-full text-sm text-left">
                                <thead className="text-xs text-slate-500 uppercase bg-slate-50/50">
                                    <tr>
                                        <th className="px-4 py-3">Microproceso</th>
                                        <th className="px-4 py-3">Analistas Responsables</th>
                                        <th className="px-4 py-3 text-right">Acciones</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-100">
                                    {rows.map((row, idx) => (
                                        <tr key={`${row.node.docId}-${idx}`} className="hover:bg-slate-50">
                                            <td className="px-4 py-3 align-top">
                                                <div className="font-bold text-slate-900">{row.node.name}</div>
                                                <div className="text-[10px] text-slate-500">{row.proc}</div>
                                            </td>
                                            <td className="px-4 py-3 align-top">
                                                <div className="text-xs text-slate-600">
                                                    {row.node.assignees?.length > 0 ? row.node.assignees.map((aid:string) => allUsers.find(u => u.id === aid)?.name).join(', ') : <span className="text-red-400 italic">Sin asignar</span>}
                                                </div>
                                            </td>
                                            <td className="px-4 py-3 align-top text-right">
                                                <button onClick={() => handleEditAssignment(projectKey, row.macro, row.proc, row.node)} className="text-slate-400 hover:text-indigo-600 p-1.5 hover:bg-indigo-50 rounded transition-colors"><Edit size={16} /></button>
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    )}
                </div>
            );
        })}
      </div>

      {showEditModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fadeIn">
            <div className="bg-white rounded-xl shadow-xl w-full max-w-md overflow-hidden">
                <div className="p-5 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
                    <h3 className="text-lg font-bold text-slate-800">Asignar Analistas: {modalMicro}</h3>
                    <button onClick={() => setShowEditModal(false)} className="text-slate-400 hover:text-slate-600"><X size={20} /></button>
                </div>
                <form onSubmit={handleSubmitAssignment} className="p-6 space-y-4">
                    <div className="space-y-1 max-h-64 overflow-y-auto border border-slate-200 rounded-lg p-2">
                        {allUsers.filter(u => u.role === UserRole.ANALYST).map(u => (
                            <label key={u.id} className="flex items-center gap-2 p-1.5 hover:bg-slate-50 rounded cursor-pointer">
                                <input 
                                    type="checkbox" 
                                    checked={currentAssignees.includes(u.id)}
                                    onChange={(e) => {
                                        if (e.target.checked) setCurrentAssignees([...currentAssignees, u.id]);
                                        else setCurrentAssignees(currentAssignees.filter(id => id !== u.id));
                                    }}
                                    className="w-4 h-4 text-indigo-600 border-slate-300 rounded focus:ring-indigo-500"
                                />
                                <span className="text-sm text-slate-700">{u.name}</span>
                            </label>
                        ))}
                    </div>

                    <div className="flex justify-end pt-4 gap-3">
                        <button type="button" onClick={() => setShowEditModal(false)} className="px-4 py-2 text-slate-600 font-medium">Cancelar</button>
                        <button type="submit" className="px-6 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 font-bold shadow-md">Guardar Cambios</button>
                    </div>
                </form>
            </div>
          </div>
      )}
    </div>
  );
};

